import React, { useState } from 'react';
import { FileText, Send, Clock, CheckCircle, AlertCircle, X } from 'lucide-react';

const FeeWaiverRequest = ({ onNavigate, debugMode }) => {
  const [showForm, setShowForm] = useState(false);
  const [requests, setRequests] = useState([
    {
      id: 'FWR001',
      studentId: '2021001234',
      studentName: 'Nguyên Vân A',
      requestType: 'Hoàn phí',
      amount: 2000000,
      reason: 'Hoàn cân hoàn phí do hoàn thành khóa hoc',
      status: 'pending',
      submittedDate: '2024-01-15',
      processedDate: null
    },
    {
      id: 'FWR002',
      studentId: '2021005678',
      studentName: 'Trân Thi B',
      requestType: 'Miên giâm',
      amount: 5000000,
      reason: 'Miên giâm 50% do hoàn cân kinh khô',
      status: 'preliminary',
      submittedDate: '2024-01-14',
      processedDate: '2024-01-15'
    },
    {
      id: 'FWR003',
      studentId: '2021009012',
      studentName: 'Lê Vân C',
      requestType: 'Hoàn phí',
      amount: 3000000,
      reason: 'Hoàn phí do rút môn',
      status: 'completed',
      submittedDate: '2024-01-10',
      processedDate: '2024-01-12'
    }
  ]);

  const [formData, setFormData] = useState({
    requestType: 'refund',
    amount: '',
    reason: ''
  });

  const getStatusColor = (status) => {
    switch(status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800';
      case 'preliminary': return 'bg-blue-100 text-blue-800';
      case 'completed': return 'bg-green-100 text-green-800';
      case 'rejected': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusText = (status) => {
    switch(status) {
      case 'pending': return 'Chô duyêt';
      case 'preliminary': return 'Duyêt sô bô (CCB) [STRQ07]';
      case 'completed': return 'Hoàn tâtc';
      case 'rejected': return 'Tû chôi';
      default: return 'Không xác dinh';
    }
  };

  const getStatusIcon = (status) => {
    switch(status) {
      case 'pending': return <Clock className="w-4 h-4" />;
      case 'preliminary': return <CheckCircle className="w-4 h-4" />;
      case 'completed': return <CheckCircle className="w-4 h-4" />;
      case 'rejected': return <X className="w-4 h-4" />;
      default: return <AlertCircle className="w-4 h-4" />;
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const newRequest = {
      id: `FWR${String(requests.length + 1).padStart(3, '0')}`,
      studentId: '2021001234',
      studentName: 'Nguyên Vân A',
      requestType: formData.requestType === 'refund' ? 'Hoàn phí' : 'Miên giâm',
      amount: parseInt(formData.amount),
      reason: formData.reason,
      status: 'pending',
      submittedDate: new Date().toISOString().split('T')[0],
      processedDate: null
    };

    setRequests([newRequest, ...requests]);
    setFormData({ requestType: 'refund', amount: '', reason: '' });
    setShowForm(false);

    alert('Gûi yêu câu thành công! [UC04]');
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('vi-VN', {
      style: 'currency',
      currency: 'VND'
    }).format(amount);
  };

  return (
    <div className="p-6">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-teal-900 mb-2">
          Gûi yêu câu hoàn phí/miên giâm
          {debugMode && <span className="badge-traceability">[UC04]</span>}
        </h1>
        <p className="text-teal-600">Quân lý và theo dõi yêu câu hoàn phí, miên giâm hoc phí</p>
      </div>

      {/* New Request Button */}
      <div className="mb-6">
        <button
          onClick={() => setShowForm(!showForm)}
          className="btn-primary flex items-center gap-2"
        >
          <FileText className="w-4 h-4" />
          Gûi yêu câu mui [UC04]
        </button>
      </div>

      {/* Request Form */}
      {showForm && (
        <div className="card mb-6">
          <h2 className="text-lg font-semibold text-gray-900 mb-4">
            Tao yêu câu mui
          </h2>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Loai yêu câu
              </label>
              <select
                value={formData.requestType}
                onChange={(e) => setFormData({...formData, requestType: e.target.value})}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-hce-blue focus:border-transparent"
              >
                <option value="refund">Hoàn phí</option>
                <option value="exemption">Miên giâm</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Sô tiên (VND)
              </label>
              <input
                type="number"
                value={formData.amount}
                onChange={(e) => setFormData({...formData, amount: e.target.value})}
                placeholder="Nhâp sô tiên yêu câu"
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-hce-blue focus:border-transparent"
                required
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Ly do
              </label>
              <textarea
                value={formData.reason}
                onChange={(e) => setFormData({...formData, reason: e.target.value})}
                placeholder="Mô ta ly do yêu câu"
                rows={4}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-hce-blue focus:border-transparent"
                required
              />
            </div>

            <div className="flex gap-3">
              <button
                type="submit"
                className="btn-primary flex items-center gap-2"
              >
                <Send className="w-4 h-4" />
                Gûi yêu câu
              </button>
              <button
                type="button"
                onClick={() => setShowForm(false)}
                className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors"
              >
                Hûy
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Requests List */}
      <div className="card">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">
          Lich sô yêu câu
        </h2>

        <div className="space-y-4">
          {requests.map((request) => (
            <div key={request.id} className="border border-gray-200 rounded-lg p-4">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center space-x-3 mb-2">
                    <h3 className="font-medium text-gray-900">{request.studentName}</h3>
                    <span className="text-sm text-gray-500">({request.studentId})</span>
                    <span className={`px-2 py-1 text-xs rounded-full ${getStatusColor(request.status)}`}>
                      <div className="flex items-center gap-1">
                        {getStatusIcon(request.status)}
                        {getStatusText(request.status)}
                      </div>
                    </span>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                    <div>
                      <span className="text-gray-600">Loai yêu câu:</span>
                      <span className="ml-2 font-medium">{request.requestType}</span>
                    </div>
                    <div>
                      <span className="text-gray-600">Sô tiên:</span>
                      <span className="ml-2 font-medium">{formatCurrency(request.amount)}</span>
                    </div>
                    <div>
                      <span className="text-gray-600">Ngây gûi:</span>
                      <span className="ml-2">{request.submittedDate}</span>
                    </div>
                    {request.processedDate && (
                      <div>
                        <span className="text-gray-600">Ngây xû ly:</span>
                        <span className="ml-2">{request.processedDate}</span>
                      </div>
                    )}
                  </div>

                  <div className="mt-3">
                    <span className="text-gray-600 text-sm">Ly do:</span>
                    <p className="text-gray-900 mt-1">{request.reason}</p>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default FeeWaiverRequest;
